// 1. Get the call_ids from the Direct Input (the node immediately before this one)
// We use .map() to create an array of all call_ids present in the input
const validCallIds = $input.all().map(item => item.json.message?.content?.call_id).filter(id => id);

// 2. Reference the "Call Completed?7" node
const allCallItems = $('Call Completed?7').all();

// 3. Filter and Map the data
// Only keep items where the 'id' exists in our 'validCallIds' array
return allCallItems
  .filter(item => validCallIds.includes(item.json.id))
  .map(item => {
    const data = item.json;

    // Get phone number and remove '+' if it exists
    let phoneNumber = data.customer?.number || '';
    if (phoneNumber.startsWith('+')) {
      phoneNumber = phoneNumber.substring(1);
    }

    // Extract transcript with error handling
    const transcript = data.transcript || "null";

    // Extract timestamps with error handling
    const startedAt = data.startedAt || "null";
    const endedAt = data.endedAt || "null";

    // Extract minutes from costs array with error handling
    // Note: Checking if data.costs exists before accessing index 0
    const minutes = data.costs?.[0]?.minutes || 0;

    // Extract endedReason
    const endedReason = data.endedReason || null;

    // Extract type
    const callType = data.type || "null";

    // Extract assistantId
    const assistantId = data.assistantId || null;

    return {
      json: {
        callId: data.id,
        assistantId: assistantId,
        summary: data.summary || "null",
        phoneNumber: phoneNumber,
        transcript: transcript,
        startedAt: startedAt,
        endedAt: endedAt,
        minutes: minutes,
        endedReason: endedReason,
        type: callType,
        artifact: {
          recordingUrl: data.artifact?.recordingUrl || data.recordingUrl || null,
          stereoRecordingUrl: data.artifact?.stereoRecordingUrl || null
        },
        httpRequestData: {
          status: "completed",
          calling_link: data.artifact?.recordingUrl || data.recordingUrl || null,
          description: data.summary || "null"
        }
      }
    };
  } );

