    // Extract JSON data for the CURRENT item
    const data = item.json || item;

    // --- VALIDATIONS ---
    // SYSTEM PROMPT - Extract from model.messages
    const systemContent = data.model?.messages?.[0]?.content?.trim();
    if (!systemContent) throw new Error("❌ System prompt missing!");

    // FIRST MESSAGE LOGIC
    // Get the welcome message if it exists
    const baseWelcomeMessage = (data.firstMessage || "").trim();

    // Default greeting to use (as requested: a simple space " " if welcome message is not available)
    const firstMessage = baseWelcomeMessage || " ";

    // VOICE - Extract from voice object
    const voiceId = data.voice?.voiceId || "Kylie";

    // VOICE PROVIDER - Extract from voice object or default
    const voiceProvider = data.voice?.provider || "vapi";

    // LANGUAGE - Extract from transcriber
    const language = data.transcriber?.language || "en";

    // ASSISTANT NAME
    const botName = data.name || "assistant";

    // MODEL
    const model = data.model?.model || "gpt-4o-mini";

    // BACKGROUND SOUND
    const backgroundSound = data.backgroundSound || "office";

    // --- CUSTOMER PHONE (if provided) ---
    const customerNumber = data.customer?.number || null;

    // --- VOICE CONFIGURATION ---
    const voiceConfig = {
        provider: voiceProvider,
        voiceId: voiceId
    };

    // Add model: "aura-2" if provider is deepgram
    if (voiceProvider.toLowerCase() === "deepgram") {
        voiceConfig.model = "aura-2";
    }

    // Return the formatted JSON for this specific item
    return {
        json: {
            name: botName,
            firstMessage: firstMessage,
            voicemailDetection: {
                provider: "openai",
