// 1. Create a Set of all phone numbers that have an associated call record
const phoneNumbersWithCalls = new Set();

for (const item of $input.all()) {
  const data = item.json;
  // If "call_type" exists, it's a call record
  if (data.call_type) {
    const phone = data.phone || data.phone_number;
    if (phone) {
      phoneNumbersWithCalls.add(phone);
    }
  }
}

// 2. Filter the items
// We keep only items that:
// - Do NOT have a "call_type" field
// - AND do NOT have a phone number that appeared in a call record
return $input.all().filter(item => {
  const data = item.json;

  // Rule 1: Remove if it's a call record itself
  if (data.call_type) {
    return false;
  }

  // Rule 2: Remove if the phone number matches a call record's phone number
  const phone = data.phone_number || data.phone;
  if (phone && phoneNumbersWithCalls.has(phone)) {
    return false;
  }

  // Keep the item if it passes both checks
  return true;
});

// Reference the "Call Completed?7" node specifically
const items = $('Call Completed?8').all();

return items.map(item => {
  const data = item.json;

  // Get phone number and remove '+' if it exists
  let phoneNumber = data.customer?.number || '';
  if (phoneNumber.startsWith('+')) {
    phoneNumber = phoneNumber.substring(1);
  }

  // Extract transcript with error handling
  const transcript = data.transcript || "null";

  // Extract timestamps with error handling
  const startedAt = data.startedAt || "null";
  const endedAt = data.endedAt || "null";

  // Extract minutes from costs array with error handling
  const minutes = data.costs?.[0]?.minutes || 0;

  // Extract endedReason
  const endedReason = data.endedReason || null;

  // Extract type
